// Test stackalloc with Span<nint> and Span<nuint>

Console.WriteLine($"nint size: {nint.Size} bytes");

Span<nint> signed = stackalloc nint[5];
for (int i = 0; i < signed.Length; i++)
    signed[i] = i * 10;

Console.WriteLine("Span<nint> via stackalloc:");
foreach (var val in signed)
    Console.Write($"  {val}");
Console.WriteLine();

Span<nuint> unsigned = stackalloc nuint[3];
unsigned[0] = 100;
unsigned[1] = 200;
unsigned[2] = 300;

Console.WriteLine("Span<nuint> via stackalloc:");
foreach (var val in unsigned)
    Console.Write($"  {val}");
Console.WriteLine();

Console.WriteLine("Success!");

